/* ============================================================
   THE TRUTH MACHINE — JavaScript
   Demonstrates JavaScript boolean, truthy, and falsy behavior
   ============================================================ */

"use strict";

// ============================================================
// STATE — single source of truth (pun intended)
// ============================================================
const state = {
	answers: {
		q1: null, // radio: true/false
		q2: null, // text input: truthy/falsy via !!value
		q3: null, // checkbox quiz: score-based
		q4: null, // slider: 0 = falsy
		q5: null // trick question: "false" string
	},
	score: 0,
	totalAnswered: 0
};

// ============================================================
// PURE BOOLEAN UTILITIES
// ============================================================

/**
 * toBoolean — maps a user input value to a JavaScript boolean
 * using actual JS truthy/falsy rules. This IS the challenge theme.
 * @param {*} value - any JS value
 * @returns {boolean}
 */
function toBoolean(value) {
	return !!value;
}

/**
 * parseEdgeCase — converts our edge-case button data-val strings
 * to the actual JS values they represent
 * @param {string} key
 * @returns {*} the actual JS value
 */
function parseEdgeCase(key) {
	const map = {
		0: 0, // falsy: number zero
		"": "", // falsy: empty string
		"0str": "0", // TRUTHY: non-empty string
		false_str: "false", // TRUTHY: non-empty string
		space: " ", // TRUTHY: whitespace string
		null: null, // falsy: null
		NaN: NaN, // falsy: NaN
		1: 1 // TRUTHY: number 1
	};
	return Object.prototype.hasOwnProperty.call(map, key) ? map[key] : key;
}

/**
 * getEdgeCaseMicrocopy — returns educational microcopy for edge cases
 * @param {string} key
 * @returns {string}
 */
function getEdgeCaseMicrocopy(key) {
	const copy = {
		0: "0 is falsy — the only falsy number (besides -0 and 0n)",
		"": 'Empty string "" is falsy. No characters = no truth.',
		"0str": "\"0\" is truthy — it's a non-empty string! Looks zero, isn't falsy.",
		false_str: '"false" is truthy — it\'s a string, not the boolean false.',
		space: '" " is truthy — whitespace counts as content.',
		null: "null is falsy — intentional absence of value.",
		NaN: "NaN is falsy — Not a Number means not truthy either.",
		1: "1 is truthy. Any non-zero number is truthy."
	};
	return copy[key] || "";
}

/**
 * getDisplayString — renders an actual JS value as a display string
 * @param {*} value
 * @returns {string}
 */
function getDisplayString(value) {
	if (value === null) return "null";
	if (value === undefined) return "undefined";
	if (typeof value === "string") return `"${value}"`;
	if (typeof value === "number" && isNaN(value)) return "NaN";
	return String(value);
}

/**
 * calculateTruthScore — normalized 0–1 based on answered questions
 * @param {object} answers
 * @returns {number} 0–1
 */
function calculateTruthScore(answers) {
	const values = Object.values(answers).filter((v) => v !== null);
	if (values.length === 0) return 0;
	const trueCount = values.filter(Boolean).length;
	return trueCount / values.length;
}

/**
 * getVerdict — returns a theme string based on score
 * @param {number} score - 0 to 1
 * @param {number} answered - how many questions answered
 * @returns {string} 'neutral' | 'truthy' | 'falsy' | 'schrodinger'
 */
function getVerdict(score, answered) {
	if (answered === 0) return "neutral";
	if (score === 0.5) return "schrodinger";
	if (score > 0.5) return "truthy";
	return "falsy";
}

// ============================================================
// DOM HELPERS
// ============================================================

const $ = (sel) => document.querySelector(sel);
const $$ = (sel) => document.querySelectorAll(sel);

function setBadge(id, value) {
	const el = $(`#badge-${id}`);
	if (!el) return;
	// null = unanswered
	if (value === null) {
		el.textContent = "—";
		el.className = "tm-verdict-badge";
		return;
	}
	// Boolean: true renders as TRUTHY, false as FALSY
	const isTruthy = toBoolean(value);
	el.textContent = isTruthy ? "✓ TRUTHY" : "✗ FALSY";
	el.className = `tm-verdict-badge tm-verdict-badge--${
		isTruthy ? "true" : "false"
	}`;
}

function setCardState(id, value) {
	const card = $(`#card-${id}`);
	if (!card) return;
	card.classList.remove("tm-card--truthy", "tm-card--falsy");
	if (value === null) return;
	card.classList.add(toBoolean(value) ? "tm-card--truthy" : "tm-card--falsy");
}

// ============================================================
// UI UPDATE — called whenever state changes
// ============================================================

function updateUI() {
	const score = calculateTruthScore(state.answers);
	state.score = score;
	const answered = Object.values(state.answers).filter((v) => v !== null).length;
	const verdict = getVerdict(score, answered);
	const percent = Math.round(score * 100);

	// --- Meter ---
	const meterFill = $("#meterFill");
	const meterScore = $("#meterScore");
	const meterTrack = $(".tm-meter__track");
	const meterVerdict = $("#meterVerdict");

	meterFill.style.height = `${percent}%`;
	meterScore.textContent = answered > 0 ? `${percent}%` : "";
	meterTrack.setAttribute("aria-valuenow", percent);

	// --- Theme class on root ---
	const machine = $("#truthMachine");
	machine.classList.remove(
		"truth-machine--truthy",
		"truth-machine--falsy",
		"truth-machine--schrodinger"
	);
	if (verdict !== "neutral") {
		machine.classList.add(`truth-machine--${verdict}`);
	}

	// --- Verdict text in meter ---
	let verdictText = "AWAITING\nINPUT";
	if (answered > 0) {
		if (score === 1) verdictText = "ABSOLUTE\nTRUTH";
		else if (score === 0) verdictText = "PURE\nFALSEHOOD";
		else if (verdict === "schrodinger") verdictText = "SCHRÖ\nDINGER";
		else if (verdict === "truthy") verdictText = "MOSTLY\nTRUE";
		else verdictText = "MOSTLY\nFALSE";
	}
	$("#meterVerdict .tm-meter__verdict-text").innerHTML = verdictText.replace(
		"\n",
		"<br>"
	);

	// --- Announce to screen reader ---
	if (answered > 0) {
		$(
			"#liveAnnounce"
		).textContent = `Truth score: ${percent}%. ${verdictText.replace(
			"<br>",
			" "
		)}.`;
	}

	// --- Easter egg messages ---
	if (score === 1 && answered >= 3) {
		showEasterEgg(
			"⊛ ABSOLUTE TRUTH — All inputs resolve to truthy. Pure signal."
		);
	} else if (score === 0 && answered >= 3) {
		showEasterEgg(
			"⊘ PURE FALSEHOOD — Everything is falsy. The void stares back."
		);
	} else if (verdict === "schrodinger" && answered >= 2) {
		showEasterEgg(
			"◈ SCHRÖDINGER'S BOOLEAN — Equally true and false. The cat is alive and dead."
		);
	} else {
		clearEasterEgg();
	}
}

// ============================================================
// EASTER EGG BANNER
// ============================================================
let eggEl = null;

function showEasterEgg(msg) {
	if (!eggEl) {
		eggEl = document.createElement("div");
		eggEl.className = "tm-egg";
		eggEl.style.cssText = `
      position: fixed; bottom: 20px; left: 50%; transform: translateX(-50%);
      font-family: var(--font-mono); font-size: 0.7rem; letter-spacing: 0.15em;
      color: var(--accent); background: var(--surface); border: 1px solid var(--border);
      padding: 10px 20px; border-radius: 4px; z-index: 200;
      box-shadow: 0 0 20px var(--glow); max-width: 90vw; text-align: center;
      transition: opacity 0.4s ease;
    `;
		document.body.appendChild(eggEl);
	}
	eggEl.textContent = msg;
	eggEl.style.opacity = "1";
}

function clearEasterEgg() {
	if (eggEl) eggEl.style.opacity = "0";
}

// ============================================================
// Q1 — Classic radio boolean
// ============================================================
$$('input[name="q1"]').forEach((input) => {
	input.addEventListener("change", () => {
		// Store actual boolean — the answer is literally "is this true or false?"
		const isTrue = input.value === "true";
		state.answers.q1 = isTrue;
		setBadge("q1", isTrue);
		setCardState("q1", isTrue);
		updateUI();
	});
});

// ============================================================
// Q2 — Truthy/Falsy text input lab
// ============================================================

function processQ2Input(rawValue, label) {
	const raw = $("#q2raw");
	const result = $("#q2result");
	const analysis = $("#q2analysis");

	// The boolean magic — !!value is the core demo
	const isTruthy = toBoolean(rawValue);
	state.answers.q2 = isTruthy;

	raw.textContent = label || getDisplayString(rawValue);
	result.textContent = isTruthy ? "!! → true (TRUTHY)" : "!! → false (FALSY)";
	result.className = `tm-analysis__result tm-analysis__result--${
		isTruthy ? "truthy" : "falsy"
	}`;
	analysis.style.display = "flex";

	setBadge("q2", isTruthy);
	setCardState("q2", isTruthy);
	updateUI();
}

$("#q2input").addEventListener("input", (e) => {
	const raw = e.target.value;
	// Use the actual string value — non-empty strings are truthy
	processQ2Input(raw, `"${raw}"`);
});

// Edge case buttons — load actual JS values
$$(".tm-edge").forEach((btn) => {
	btn.addEventListener("click", () => {
		const key = btn.dataset.val;
		const actualValue = parseEdgeCase(key);
		const displayStr = getDisplayString(actualValue);

		// Update the input field visually
		const input = $("#q2input");
		input.value = displayStr;

		// Show microcopy hint below
		const existingHint = btn.closest(".tm-card").querySelector(".tm-edge-hint");
		if (existingHint) existingHint.remove();

		const hint = document.createElement("p");
		hint.className = "tm-card__hint tm-edge-hint";
		hint.style.color = toBoolean(actualValue)
			? "var(--c-true-accent)"
			: "var(--c-false-accent)";
		hint.textContent = getEdgeCaseMicrocopy(key);
		btn.closest(".tm-card__edgecases").after(hint);

		processQ2Input(actualValue, displayStr);
	});
});

// ============================================================
// Q3 — Checkbox quiz: score based on correct answers
// ============================================================
$$("#card-q3 .tm-check__input").forEach((checkbox) => {
	checkbox.addEventListener("change", evaluateQ3);
});

function evaluateQ3() {
	const checkboxes = $$("#card-q3 .tm-check__input");
	const checked = $$("#card-q3 .tm-check__input:checked");

	if (checked.length === 0) {
		state.answers.q3 = null;
		setBadge("q3", null);
		setCardState("q3", null);
		$("#q3hint").textContent = "";
		updateUI();
		return;
	}

	// Score: how many selections match the actual truthy property
	let correct = 0;
	let total = 0;

	checkboxes.forEach((cb) => {
		const isActuallyTruthy = cb.dataset.truthy === "true";
		const isChecked = cb.checked;
		total++;
		// Correct if: checked+truthy OR unchecked+falsy
		if (isChecked === isActuallyTruthy) correct++;
	});

	const accuracy = correct / total;
	// q3 answer is truthy if user gets > 50% correct
	const q3value = accuracy > 0.5;

	state.answers.q3 = q3value;
	setBadge("q3", q3value);
	setCardState("q3", q3value);

	const pct = Math.round(accuracy * 100);
	const hint = $("#q3hint");
	if (accuracy === 1) {
		hint.textContent = `Perfect — ${pct}% correct! You know your truthy from falsy.`;
		hint.style.color = "var(--c-true-accent)";
	} else if (accuracy >= 0.5) {
		hint.textContent = `${pct}% correct. Close — remember: "0" and [] are truthy!`;
		hint.style.color = "var(--accent)";
	} else {
		hint.textContent = `${pct}% correct. Falsy values in JS are rarer than you think!`;
		hint.style.color = "var(--c-false-accent)";
	}

	updateUI();
}

// ============================================================
// Q4 — Slider: 0 is the only falsy number
// ============================================================
const slider = $("#q4slider");
const sliderOutput = $("#q4output");

slider.addEventListener("input", () => {
	const val = Number(slider.value);
	sliderOutput.textContent = val;

	// JavaScript coerces 0 to false — key demo point
	const isTruthy = toBoolean(val);
	state.answers.q4 = isTruthy;
	setBadge("q4", isTruthy);
	setCardState("q4", isTruthy);

	// Visual feedback on output
	sliderOutput.style.color = isTruthy
		? "var(--c-true-accent)"
		: "var(--c-false-accent)";
	sliderOutput.style.textShadow = isTruthy
		? "0 0 20px rgba(0,255,136,0.5)"
		: "0 0 20px rgba(255,0,64,0.5)";

	updateUI();
});

// ============================================================
// Q5 — Trick question: "false" (string) is truthy
// ============================================================
$$('input[name="q5"]').forEach((input) => {
	input.addEventListener("change", () => {
		// The CORRECT answer: "false" string is TRUTHY (not falsy)
		// User selects "Yes, it's falsy" = value "true" = WRONG
		// User selects "No, it's truthy" = value "false" = CORRECT
		const userSaysItsFalsy = input.value === "true";
		const isCorrect = !userSaysItsFalsy; // correct = it IS truthy, not falsy

		state.answers.q5 = isCorrect;
		setBadge("q5", isCorrect);
		setCardState("q5", isCorrect);

		const reveal = $("#q5reveal");
		if (userSaysItsFalsy) {
			reveal.textContent =
				'✗ Trick! "false" is a non-empty string — JavaScript sees it as truthy.';
			reveal.style.color = "var(--c-false-accent)";
		} else {
			reveal.textContent =
				"✓ Correct! Only the boolean false (not the string) is falsy.";
			reveal.style.color = "var(--c-true-accent)";
		}

		updateUI();
	});
});

// ============================================================
// RANDOMIZE — dramatic jump between states
// ============================================================
$("#btnRandomize").addEventListener("click", () => {
	// Randomize all radio questions
	const q1 = Math.random() > 0.5;
	$$('input[name="q1"]').forEach((r) => {
		r.checked = (r.value === "true") === q1;
	});
	state.answers.q1 = q1;
	setBadge("q1", q1);
	setCardState("q1", q1);

	// Randomize text input — pick a random edge case
	const edgeKeys = ["0", "", "0str", "false_str", "space", "null", "NaN", "1"];
	const randomKey = edgeKeys[Math.floor(Math.random() * edgeKeys.length)];
	const randomVal = parseEdgeCase(randomKey);
	$("#q2input").value = getDisplayString(randomVal);
	processQ2Input(randomVal, getDisplayString(randomVal));

	// Randomize checkboxes
	$$("#card-q3 .tm-check__input").forEach((cb) => {
		cb.checked = Math.random() > 0.5;
	});
	evaluateQ3();

	// Randomize slider
	const sliderVal = Math.floor(Math.random() * 11) - 5;
	slider.value = sliderVal;
	slider.dispatchEvent(new Event("input"));

	// Randomize Q5
	const q5 = Math.random() > 0.5;
	$$('input[name="q5"]').forEach((r) => {
		r.checked = (r.value === "true") === q5;
	});
	$$('input[name="q5"]')[0].dispatchEvent(new Event("change"));

	updateUI();
});

// ============================================================
// RESET — clear everything
// ============================================================
$("#btnReset").addEventListener("click", () => {
	// Clear all radio/checkbox inputs
	$$('input[type="radio"], input[type="checkbox"]').forEach((i) => {
		i.checked = false;
	});

	// Clear text input
	$("#q2input").value = "";
	const raw = $("#q2raw");
	const result = $("#q2result");
	raw.textContent = "";
	result.textContent = "";
	result.className = "tm-analysis__result";

	// Reset slider
	slider.value = 0;
	sliderOutput.textContent = "0";
	sliderOutput.style.color = "";
	sliderOutput.style.textShadow = "";

	// Clear reveal text
	$("#q5reveal").textContent = "";
	$("#q3hint").textContent = "";

	// Remove edge case hints
	$$(".tm-edge-hint").forEach((h) => h.remove());

	// Reset state
	Object.keys(state.answers).forEach((k) => {
		state.answers[k] = null;
	});
	state.score = 0;

	// Reset badges and card states
	Object.keys(state.answers).forEach((k) => {
		setBadge(k, null);
		setCardState(k, null);
	});

	updateUI();
});

// ============================================================
// INIT — set initial state
// ============================================================
(function init() {
	// Initialize slider to show boolean value of 0
	sliderOutput.textContent = "0";
	sliderOutput.style.color = "var(--c-false-accent)";

	// Call updateUI to set initial neutral state
	updateUI();
})();

style.css:
/* ============================================================
   THE TRUTH MACHINE — CSS
   Aesthetic: Retro-Terminal meets Glassmorphic Duality
   ============================================================ */

/* --- GOOGLE FONTS --- */
@import url("https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Bebas+Neue&family=DM+Sans:ital,wght@0,300;0,500;1,300&display=swap");

/* ============================================================
   1. CUSTOM PROPERTIES — Theme System
   ============================================================ */
:root {
	/* TRUE theme — phosphor green terminal */
	--c-true-bg: #050e0a;
	--c-true-surface: #0a1a12;
	--c-true-border: #1aff7a;
	--c-true-accent: #00ff88;
	--c-true-glow: rgba(0, 255, 136, 0.18);
	--c-true-text: #d4ffe9;
	--c-true-dim: #3a6b52;
	--c-true-meter: #00ff88;

	/* FALSE theme — corrupted crimson */
	--c-false-bg: #0e0507;
	--c-false-surface: #1a0a0e;
	--c-false-border: #ff1a4b;
	--c-false-accent: #ff0040;
	--c-false-glow: rgba(255, 0, 64, 0.18);
	--c-false-text: #ffd4dd;
	--c-false-dim: #6b2030;
	--c-false-meter: #ff0040;

	/* NEUTRAL (initial) */
	--c-neutral-bg: #080810;
	--c-neutral-surface: #10101e;
	--c-neutral-border: #4040a0;
	--c-neutral-accent: #8080ff;
	--c-neutral-text: #c8c8ff;
	--c-neutral-dim: #2a2a50;

	/* Active theme tokens (start neutral) */
	--bg: var(--c-neutral-bg);
	--surface: var(--c-neutral-surface);
	--border: var(--c-neutral-border);
	--accent: var(--c-neutral-accent);
	--glow: var(--c-neutral-surface);
	--text: var(--c-neutral-text);
	--dim: var(--c-neutral-dim);
	--meter-color: var(--c-neutral-accent);

	/* Typography */
	--font-mono: "Share Tech Mono", "Courier New", monospace;
	--font-display: "Bebas Neue", "Impact", sans-serif;
	--font-body: "DM Sans", sans-serif;

	/* Layout */
	--gap: clamp(12px, 2vw, 24px);
	--radius: 4px;
	--meter-w: 56px;

	/* Transitions */
	--transition-theme: background 0.8s ease, color 0.8s ease,
		border-color 0.5s ease;
}

/* --- TRUE dominant state --- */
.truth-machine--truthy {
	--bg: var(--c-true-bg);
	--surface: var(--c-true-surface);
	--border: var(--c-true-border);
	--accent: var(--c-true-accent);
	--glow: var(--c-true-glow);
	--text: var(--c-true-text);
	--dim: var(--c-true-dim);
	--meter-color: var(--c-true-meter);
}

/* --- FALSE dominant state --- */
.truth-machine--falsy {
	--bg: var(--c-false-bg);
	--surface: var(--c-false-surface);
	--border: var(--c-false-border);
	--accent: var(--c-false-accent);
	--glow: var(--c-false-glow);
	--text: var(--c-false-text);
	--dim: var(--c-false-dim);
	--meter-color: var(--c-false-meter);
}

/* ============================================================
   2. RESET & BASE
   ============================================================ */
*,
*::before,
*::after {
	box-sizing: border-box;
	margin: 0;
	padding: 0;
}

html {
	font-size: 16px;
	-webkit-font-smoothing: antialiased;
}

body {
	background: #030308;
	min-height: 100vh;
	padding: 0;
	overflow-x: hidden;
}

.sr-only {
	position: absolute;
	width: 1px;
	height: 1px;
	padding: 0;
	overflow: hidden;
	clip: rect(0, 0, 0, 0);
	white-space: nowrap;
	border: 0;
}

/* ============================================================
   3. MAIN CONTAINER
   ============================================================ */
.truth-machine {
	position: relative;
	min-height: 100vh;
	background: var(--bg, #080810);
	color: var(--text, #c8c8ff);
	font-family: var(--font-body);
	transition: var(--transition-theme);
	padding: clamp(16px, 4vw, 40px) clamp(16px, 5vw, 48px);
	padding-bottom: 80px;
	isolation: isolate;
	overflow: hidden;
}

/* ============================================================
   4. ATMOSPHERIC EFFECTS (Scanlines, Noise, Glow)
   ============================================================ */

/* CRT scanlines overlay */
.scanlines {
	position: fixed;
	inset: 0;
	pointer-events: none;
	z-index: 100;
	background: repeating-linear-gradient(
		to bottom,
		transparent 0px,
		transparent 3px,
		rgba(0, 0, 0, 0.08) 3px,
		rgba(0, 0, 0, 0.08) 4px
	);
}

/* Noise texture */
.noise {
	position: fixed;
	inset: 0;
	pointer-events: none;
	z-index: 99;
	opacity: 0.035;
	background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='1'/%3E%3C/svg%3E");
	background-size: 150px 150px;
}

/* Ambient radial glow from top-left */
.truth-machine::before {
	content: "";
	position: fixed;
	top: -20%;
	left: -20%;
	width: 70%;
	height: 70%;
	background: radial-gradient(
		ellipse,
		var(--glow, transparent) 0%,
		transparent 70%
	);
	pointer-events: none;
	z-index: 0;
	transition: background 1.2s ease;
}

/* ============================================================
   5. HEADER
   ============================================================ */
.tm-header {
	position: relative;
	z-index: 2;
	margin-bottom: clamp(24px, 4vw, 48px);
	max-width: 680px;
}

.tm-header__eyebrow {
	display: flex;
	gap: 8px;
	margin-bottom: 12px;
	flex-wrap: wrap;
}

.tm-tag {
	font-family: var(--font-mono);
	font-size: 0.65rem;
	letter-spacing: 0.18em;
	padding: 4px 10px;
	border: 1px solid var(--border);
	color: var(--accent);
	text-transform: uppercase;
	transition: var(--transition-theme);
}

.tm-tag--week {
	color: var(--dim);
	border-color: var(--dim);
}

.tm-title {
	font-family: var(--font-display);
	line-height: 0.88;
	margin-bottom: 16px;
}

.tm-title__the {
	display: block;
	font-size: clamp(1.4rem, 4vw, 2.2rem);
	color: var(--dim);
	letter-spacing: 0.3em;
	transition: color 0.8s ease;
}

.tm-title__main {
	display: block;
	font-size: clamp(4rem, 12vw, 8rem);
	color: var(--accent);
	text-shadow: 0 0 40px var(--glow), 0 0 80px var(--glow);
	letter-spacing: 0.06em;
	transition: color 0.8s ease, text-shadow 0.8s ease;
}

.tm-subtitle {
	font-size: clamp(0.8rem, 1.5vw, 0.95rem);
	font-weight: 300;
	color: var(--dim);
	font-style: italic;
	line-height: 1.6;
	max-width: 480px;
	transition: color 0.8s ease;
}

/* ============================================================
   6. LAYOUT GRID
   ============================================================ */
.tm-layout {
	position: relative;
	z-index: 2;
	display: grid;
	grid-template-columns: var(--meter-w) 1fr;
	gap: var(--gap);
	align-items: start;
}

@media (max-width: 540px) {
	.tm-layout {
		grid-template-columns: 40px 1fr;
	}
}

/* ============================================================
   7. TRUTH METER
   ============================================================ */
.tm-meter {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 8px;
	position: sticky;
	top: 24px;
}

.tm-meter__label {
	font-family: var(--font-mono);
	font-size: 0.55rem;
	letter-spacing: 0.15em;
	color: var(--dim);
	text-transform: uppercase;
	writing-mode: vertical-rl;
	transition: color 0.8s ease;
}

.tm-meter__label--top {
	color: var(--c-true-accent);
}
.tm-meter__label--bottom {
	color: var(--c-false-accent);
}

.tm-meter__track {
	position: relative;
	width: 28px;
	height: clamp(200px, 40vh, 360px);
	border: 1px solid var(--border);
	background: rgba(0, 0, 0, 0.4);
	overflow: hidden;
	border-radius: 14px;
	transition: border-color 0.6s ease;
	box-shadow: 0 0 16px var(--glow), inset 0 0 8px rgba(0, 0, 0, 0.6);
}

.tm-meter__fill {
	position: absolute;
	bottom: 0;
	left: 0;
	right: 0;
	height: 0%;
	background: linear-gradient(to top, var(--c-false-meter), var(--c-true-meter));
	/* JavaScript will set height via inline style */
	border-radius: 0 0 14px 14px;
	box-shadow: 0 -4px 20px var(--glow);
}

.tm-meter__score {
	position: absolute;
	inset: 0;
	display: flex;
	align-items: center;
	justify-content: center;
	font-family: var(--font-mono);
	font-size: 0.55rem;
	color: #fff;
	mix-blend-mode: overlay;
	writing-mode: vertical-rl;
	letter-spacing: 0.1em;
}

.tm-meter__ticks {
	position: absolute;
	inset: 0;
	display: flex;
	flex-direction: column;
	justify-content: space-between;
	padding: 4px;
	pointer-events: none;
}

.tm-meter__ticks span {
	display: block;
	height: 1px;
	background: var(--dim);
	opacity: 0.3;
	width: 100%;
}

.tm-meter__verdict {
	margin-top: 4px;
}

.tm-meter__verdict-text {
	display: block;
	font-family: var(--font-mono);
	font-size: 0.5rem;
	letter-spacing: 0.1em;
	text-align: center;
	color: var(--accent);
	text-transform: uppercase;
	transition: color 0.8s ease;
	writing-mode: vertical-rl;
	line-height: 1.2;
}

/* ============================================================
   8. QUESTION CARDS
   ============================================================ */
.tm-questions {
	display: flex;
	flex-direction: column;
	gap: var(--gap);
}

.tm-card {
	background: var(--surface);
	border: 1px solid var(--border);
	padding: clamp(14px, 2.5vw, 24px);
	border-radius: var(--radius);
	transition: var(--transition-theme), box-shadow 0.4s ease;
	position: relative;
	overflow: hidden;
}

/* Glow pulse on card with truthy result */
.tm-card--truthy {
	box-shadow: 0 0 0 1px var(--c-true-border), 0 0 20px var(--c-true-glow);
}

/* Glow on falsy result */
.tm-card--falsy {
	box-shadow: 0 0 0 1px var(--c-false-border), 0 0 20px var(--c-false-glow);
}

/* Left stripe using :has() — CSS-only boolean logic demo */
.tm-card::before {
	content: "";
	position: absolute;
	left: 0;
	top: 0;
	bottom: 0;
	width: 3px;
	background: var(--dim);
	transition: background 0.4s ease;
}

/* CSS :has() — card with a checked radio turns true/false stripe */
.tm-card:has(input[type="radio"][value="true"]:checked)::before {
	background: var(--c-true-accent);
}
.tm-card:has(input[type="radio"][value="false"]:checked)::before {
	background: var(--c-false-accent);
}

/* Trick card special style */
.tm-card--trick {
	border-style: dashed;
}

.tm-card__legend {
	display: flex;
	align-items: center;
	gap: 10px;
	margin-bottom: 14px;
	border: none;
	padding: 0;
	width: auto;
}

.tm-card__num {
	font-family: var(--font-mono);
	font-size: 0.65rem;
	color: var(--dim);
	letter-spacing: 0.1em;
	transition: color 0.8s ease;
}

.tm-card__type {
	font-family: var(--font-mono);
	font-size: 0.6rem;
	letter-spacing: 0.2em;
	color: var(--accent);
	text-transform: uppercase;
	transition: color 0.8s ease;
}

.tm-card__prompt {
	font-size: clamp(0.85rem, 1.8vw, 1rem);
	font-weight: 300;
	line-height: 1.5;
	margin-bottom: 16px;
	color: var(--text);
	transition: color 0.8s ease;
}

.tm-card__hint {
	font-family: var(--font-mono);
	font-size: 0.72rem;
	color: var(--dim);
	margin-top: 10px;
	min-height: 1.4em;
	transition: color 0.8s ease;
}

.tm-card__reveal {
	font-family: var(--font-mono);
	font-size: 0.75rem;
	color: var(--accent);
	margin-top: 10px;
	min-height: 1.4em;
	transition: color 0.8s ease;
}

/* ============================================================
   9. RADIO CONTROLS
   ============================================================ */
.tm-card__controls {
	display: flex;
	gap: 16px;
	flex-wrap: wrap;
}

.tm-radio {
	display: flex;
	align-items: center;
	gap: 8px;
	cursor: pointer;
}

.tm-radio__input {
	position: absolute;
	opacity: 0;
	width: 0;
	height: 0;
}

.tm-radio__mark {
	width: 18px;
	height: 18px;
	border: 1.5px solid var(--border);
	border-radius: 50%;
	position: relative;
	flex-shrink: 0;
	transition: border-color 0.3s ease;
}

.tm-radio__mark::after {
	content: "";
	position: absolute;
	inset: 3px;
	border-radius: 50%;
	background: transparent;
	transition: background 0.3s ease;
}

.tm-radio__input:checked + .tm-radio__mark {
	border-color: var(--accent);
}

.tm-radio__input:checked + .tm-radio__mark::after {
	background: var(--accent);
	box-shadow: 0 0 6px var(--accent);
}

/* CSS :has() — radio label turns bright when checked */
.tm-radio:has(.tm-radio__input:checked) .tm-radio__text {
	color: var(--accent);
}

.tm-radio__input:focus-visible + .tm-radio__mark {
	outline: 2px solid var(--accent);
	outline-offset: 3px;
}

.tm-radio__text {
	font-family: var(--font-mono);
	font-size: 0.85rem;
	color: var(--dim);
	transition: color 0.3s ease;
}

/* ============================================================
   10. TEXT INPUT (Q2 — Truthy/Falsy Lab)
   ============================================================ */
.tm-card__controls--text {
	flex-direction: column;
	align-items: stretch;
	gap: 10px;
}

.tm-input {
	background: rgba(0, 0, 0, 0.5);
	border: 1px solid var(--border);
	color: var(--text);
	font-family: var(--font-mono);
	font-size: 0.9rem;
	padding: 10px 14px;
	border-radius: var(--radius);
	outline: none;
	width: 100%;
	transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.tm-input::placeholder {
	color: var(--dim);
	opacity: 0.6;
}

.tm-input:focus-visible {
	border-color: var(--accent);
	box-shadow: 0 0 12px var(--glow);
}

/* CSS :not(:placeholder-shown) as falsy-truthy check */
.tm-input:not(:placeholder-shown) {
	border-color: var(--accent);
}

.tm-input-analysis {
	display: flex;
	align-items: center;
	gap: 10px;
	font-family: var(--font-mono);
	font-size: 0.78rem;
	flex-wrap: wrap;
	min-height: 1.5em;
}

.tm-analysis__raw {
	color: var(--dim);
	background: rgba(255, 255, 255, 0.04);
	padding: 2px 6px;
	border-radius: 2px;
	max-width: 200px;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
}

.tm-analysis__arrow {
	color: var(--dim);
}

.tm-analysis__result {
	font-weight: bold;
	letter-spacing: 0.05em;
	padding: 2px 8px;
	border-radius: 2px;
}

.tm-analysis__result--truthy {
	color: var(--c-true-accent);
	background: rgba(0, 255, 136, 0.08);
	border: 1px solid var(--c-true-dim);
}

.tm-analysis__result--falsy {
	color: var(--c-false-accent);
	background: rgba(255, 0, 64, 0.08);
	border: 1px solid var(--c-false-dim);
}

/* Edge case buttons */
.tm-card__edgecases {
	display: flex;
	flex-wrap: wrap;
	gap: 6px;
	margin-top: 4px;
}

.tm-edge {
	font-family: var(--font-mono);
	font-size: 0.7rem;
	padding: 3px 8px;
	background: rgba(0, 0, 0, 0.4);
	border: 1px solid var(--dim);
	color: var(--dim);
	cursor: pointer;
	border-radius: 2px;
	transition: all 0.2s ease;
}

.tm-edge:hover,
.tm-edge:focus-visible {
	background: var(--surface);
	border-color: var(--accent);
	color: var(--accent);
	outline: none;
}

/* ============================================================
   11. CHECKBOXES (Q3)
   ============================================================ */
.tm-card__controls--checks {
	display: grid;
	grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
	gap: 10px;
}

.tm-check {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 6px;
	cursor: pointer;
}

.tm-check__input {
	position: absolute;
	opacity: 0;
	width: 0;
	height: 0;
}

.tm-check__box {
	width: 28px;
	height: 28px;
	border: 1.5px solid var(--border);
	border-radius: var(--radius);
	position: relative;
	transition: all 0.2s ease;
	flex-shrink: 0;
}

.tm-check__box::after {
	content: "✓";
	position: absolute;
	inset: 0;
	display: flex;
	align-items: center;
	justify-content: center;
	font-size: 1rem;
	color: transparent;
	transition: color 0.2s ease;
}

/* CSS :has() for checkbox check feedback */
.tm-check:has(.tm-check__input:checked) .tm-check__box {
	border-color: var(--accent);
	background: rgba(255, 255, 255, 0.04);
}

.tm-check:has(.tm-check__input:checked) .tm-check__box::after {
	color: var(--accent);
}

.tm-check__input:focus-visible + .tm-check__box {
	outline: 2px solid var(--accent);
	outline-offset: 3px;
}

.tm-check__text {
	font-family: var(--font-mono);
	font-size: 0.75rem;
	color: var(--dim);
	text-align: center;
	transition: color 0.3s ease;
}

.tm-check:has(.tm-check__input:checked) .tm-check__text {
	color: var(--accent);
}

code {
	font-family: var(--font-mono);
	font-size: 0.85em;
	background: rgba(255, 255, 255, 0.05);
	padding: 1px 5px;
	border-radius: 2px;
}

/* ============================================================
   12. SLIDER (Q4)
   ============================================================ */
.tm-card__controls--slider {
	flex-direction: column;
	gap: 12px;
}

.tm-slider {
	-webkit-appearance: none;
	appearance: none;
	width: 100%;
	height: 6px;
	background: linear-gradient(
		to right,
		var(--c-false-meter),
		transparent 50%,
		var(--c-true-meter)
	);
	border-radius: 3px;
	outline: none;
	cursor: pointer;
}

.tm-slider::-webkit-slider-thumb {
	-webkit-appearance: none;
	appearance: none;
	width: 22px;
	height: 22px;
	border-radius: 50%;
	background: var(--accent);
	border: 2px solid var(--bg);
	box-shadow: 0 0 10px var(--accent);
	cursor: pointer;
	transition: box-shadow 0.2s ease;
}

.tm-slider::-moz-range-thumb {
	width: 22px;
	height: 22px;
	border-radius: 50%;
	background: var(--accent);
	border: 2px solid var(--bg);
	cursor: pointer;
}

.tm-slider:focus-visible::-webkit-slider-thumb {
	outline: 2px solid var(--accent);
	outline-offset: 2px;
}

.tm-slider__output {
	font-family: var(--font-display);
	font-size: 2.5rem;
	color: var(--accent);
	text-shadow: 0 0 20px var(--glow);
	text-align: center;
	display: block;
	transition: color 0.3s ease, text-shadow 0.3s ease;
	line-height: 1;
}

/* ============================================================
   13. VERDICT BADGES
   ============================================================ */
.tm-card__verdict {
	margin-top: 12px;
	min-height: 28px;
	display: flex;
	align-items: center;
}

.tm-verdict-badge {
	font-family: var(--font-mono);
	font-size: 0.72rem;
	letter-spacing: 0.12em;
	padding: 4px 10px;
	border-radius: 2px;
	text-transform: uppercase;
	background: transparent;
	border: 1px solid var(--dim);
	color: var(--dim);
	transition: all 0.3s ease;
}

.tm-verdict-badge--true {
	background: rgba(0, 255, 136, 0.06);
	border-color: var(--c-true-border);
	color: var(--c-true-accent);
	box-shadow: 0 0 8px rgba(0, 255, 136, 0.15);
}

.tm-verdict-badge--false {
	background: rgba(255, 0, 64, 0.06);
	border-color: var(--c-false-border);
	color: var(--c-false-accent);
	box-shadow: 0 0 8px rgba(255, 0, 64, 0.15);
}

/* ============================================================
   14. CONTROL BUTTONS
   ============================================================ */
.tm-controls {
	position: relative;
	z-index: 2;
	display: flex;
	gap: 12px;
	margin-top: clamp(16px, 3vw, 32px);
	flex-wrap: wrap;
}

.tm-btn {
	font-family: var(--font-mono);
	font-size: 0.8rem;
	letter-spacing: 0.15em;
	text-transform: uppercase;
	padding: 10px 22px;
	border: 1px solid var(--border);
	background: transparent;
	color: var(--accent);
	cursor: pointer;
	border-radius: var(--radius);
	display: flex;
	align-items: center;
	gap: 8px;
	transition: all 0.25s ease;
}

.tm-btn:hover {
	background: var(--surface);
	box-shadow: 0 0 14px var(--glow);
	border-color: var(--accent);
}

.tm-btn:focus-visible {
	outline: 2px solid var(--accent);
	outline-offset: 3px;
}

.tm-btn--reset {
	color: var(--dim);
	border-color: var(--dim);
}

.tm-btn--reset:hover {
	color: var(--c-false-accent);
	border-color: var(--c-false-border);
	box-shadow: 0 0 14px var(--c-false-glow);
}

.tm-btn__icon {
	font-style: normal;
	display: inline-block;
}

/* ============================================================
   15. FOOTER / LEGEND
   ============================================================ */
.tm-footer {
	position: relative;
	z-index: 2;
	margin-top: clamp(32px, 5vw, 64px);
	padding-top: clamp(16px, 2vw, 24px);
	border-top: 1px solid var(--dim);
}

.tm-legend {
	margin-bottom: 20px;
}

.tm-legend__title {
	font-family: var(--font-mono);
	font-size: 0.7rem;
	letter-spacing: 0.2em;
	text-transform: uppercase;
	color: var(--accent);
	margin-bottom: 12px;
	transition: color 0.8s ease;
}

.tm-legend__list {
	list-style: none;
	display: flex;
	flex-direction: column;
	gap: 6px;
}

.tm-legend__list li {
	font-size: 0.8rem;
	font-weight: 300;
	color: var(--dim);
	line-height: 1.5;
	padding-left: 16px;
	position: relative;
	transition: color 0.8s ease;
}

.tm-legend__list li::before {
	content: "▸";
	position: absolute;
	left: 0;
	color: var(--accent);
}

.tm-credits {
	font-size: 0.72rem;
	color: var(--dim);
	font-family: var(--font-mono);
	line-height: 1.7;
	transition: color 0.8s ease;
}

/* ============================================================
   16. ANIMATIONS
   ============================================================ */

/* Meter fill smooth animation */
.tm-meter__fill {
	transition: height 0.7s cubic-bezier(0.34, 1.56, 0.64, 1);
}

/* TRUE breathe animation */
@keyframes breathe {
	0%,
	100% {
		transform: scale(1);
		opacity: 1;
	}
	50% {
		transform: scale(1.02);
		opacity: 0.85;
	}
}

/* FALSE glitch animation */
@keyframes glitch {
	0%,
	100% {
		transform: translateX(0) skewX(0deg);
	}
	10% {
		transform: translateX(-3px) skewX(-1deg);
	}
	20% {
		transform: translateX(2px) skewX(0.5deg);
	}
	30% {
		transform: translateX(-1px) skewX(1deg);
	}
	40% {
		transform: translateX(3px) skewX(-0.5deg);
	}
	50% {
		transform: translateX(-2px) skewX(0deg);
	}
}

/* Glitch text shadow */
@keyframes glitch-text {
	0%,
	100% {
		text-shadow: 0 0 40px var(--c-false-glow);
		clip-path: none;
	}
	10% {
		text-shadow: -3px 0 var(--c-false-accent), 3px 0 var(--c-true-accent);
	}
	20% {
		text-shadow: 2px 0 var(--c-false-accent), -2px 0 var(--c-true-accent);
	}
	30% {
		text-shadow: 0 0 40px var(--c-false-glow);
	}
}

@media (prefers-reduced-motion: no-preference) {
	/* TRUE state: calm breathe on title */
	.truth-machine--truthy .tm-title__main {
		animation: breathe 4s ease-in-out infinite;
	}

	/* FALSE state: glitch on title */
	.truth-machine--falsy .tm-title__main {
		animation: glitch-text 2.5s ease-in-out infinite;
	}

	/* FALSE state: shake cards slightly */
	.truth-machine--falsy .tm-card {
		animation: glitch 8s ease-in-out infinite;
	}
	.truth-machine--falsy .tm-card:nth-child(2) {
		animation-delay: -1.5s;
	}
	.truth-machine--falsy .tm-card:nth-child(3) {
		animation-delay: -3s;
	}

	/* Meter fill animation */
	.tm-meter__fill {
		transition: height 0.8s cubic-bezier(0.34, 1.2, 0.64, 1);
	}

	/* Button hover bounce */
	.tm-btn:hover .tm-btn__icon {
		animation: breathe 0.6s ease-in-out infinite;
	}
}

/* ============================================================
   17. EASTER EGG STATES
   ============================================================ */

/* Schrödinger */
.truth-machine--schrodinger .tm-title__main {
	background: linear-gradient(
		90deg,
		var(--c-true-accent),
		var(--c-false-accent)
	);
	-webkit-background-clip: text;
	background-clip: text;
	-webkit-text-fill-color: transparent;
}

/* ============================================================
   18. SPECIAL: CSS if() DEMO (progressive enhancement)
       Wrap in @supports to avoid breaking non-supporting browsers
   ============================================================ */
@supports (color: if(style(--bg: red): red;
else: blue)) {
	.tm-card__type {
		color: if(
			style(--accent: var(--c-true-accent)): var(--c-true-accent) ; else:
				var(--c-false-accent)
		);
	}
}

/* ============================================================
   19. RESPONSIVE
   ============================================================ */
@media (max-width: 400px) {
	.tm-title__main {
		font-size: 3.5rem;
	}
	.tm-controls {
		flex-direction: column;
	}
	.tm-btn {
		justify-content: center;
	}
}
